+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7767,14 +7767,37 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,

 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
-  Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
-    return nullptr;
-
   const APFloat *C;
   if (!match(I.getOperand(1), m_APFloat(C)))
     return nullptr;

+  // Match fabs(X) or select pattern that computes absolute value.
+  Value *X = nullptr;
+  Value *Op0 = I.getOperand(0);
+  if (match(Op0, m_FAbs(m_Value(X)))) {
+    // Handled below.
+  } else if (SelectInst *SI = dyn_cast<SelectInst>(Op0)) {
+    Value *Cond = SI->getCondition();
+    Value *TrueVal = SI->getTrueValue();
+    Value *FalseVal = SI->getFalseValue();
+    Value *Y;
+    // Check if one arm is negation of the other.
+    if (match(TrueVal, m_FNeg(m_Specific(FalseVal))))
+      Y = FalseVal;
+    else if (match(FalseVal, m_FNeg(m_Specific(TrueVal))))
+      Y = TrueVal;
+    else
+      Y = nullptr;
+    if (Y) {
+      // The select computes absolute value (or negative absolute).
+      // For comparison with zero, the sign does not matter.
+      X = Y;
+    }
+  }
+
+  if (!X)
+    return nullptr;
